here are some feedbacks:
1. The match-3 logic only finds fixed-length triplets and doesn’t handle longer runs or group overlapping matches cleanly.
2. After clearing gems, there’s no gravity step to let gems above fall down, so chain reactions won’t actually occur.
3. The chain reaction only runs one extra pass; it should loop until no more clears happen.
4. It’s clearer to collect all clearable coordinates first, then clear and score in one go.

here are the changes:
```python
import pygame
import random

from task0 import GRID_WIDTH, GRID_HEIGHT, TETROMINO_SHAPES, COLOR_MAP, Gem, Tetromino, get_empty_grid


class GameState:
    def __init__(self):
        self.grid = get_empty_grid()
        self.current_tetromino = self.new_tetromino()
        self.next_tetromino = self.new_tetromino()
        self.score = 0
        self.game_over = False

    def new_tetromino(self):
        shape_key = random.choice(list(TETROMINO_SHAPES.keys()))
        tetromino = Tetromino(shape_key)
        tetromino.position = [GRID_WIDTH // 2 - 2, 0]
        return tetromino

    def hard_drop(self):
        while self.is_valid_move(self.current_tetromino, 0, 1):
            self.current_tetromino.move(0, 1)
        self.lock_tetromino()

    def move_tetromino(self, dx):
        if self.is_valid_move(self.current_tetromino, dx, 0):
            self.current_tetromino.move(dx, 0)

    def rotate_tetromino(self):
        old_rotation = self.current_tetromino.rotation_index
        old_blocks = list(self.current_tetromino.blocks)
        self.current_tetromino.rotate()
        if not self.is_valid_move(self.current_tetromino, 0, 0):
            # simple wall-kick
            for dx in (-1, 1):
                if self.is_valid_move(self.current_tetromino, dx, 0):
                    self.current_tetromino.move(dx, 0)
                    return
            # revert
            self.current_tetromino.rotation_index = old_rotation
            self.current_tetromino.blocks = old_blocks

    def is_valid_move(self, tetromino, dx, dy):
        for x, y in tetromino.blocks:
            nx, ny = x + dx, y + dy
            if nx < 0 or nx >= GRID_WIDTH or ny >= GRID_HEIGHT:
                return False
            if ny < 0:
                continue
            if self.grid[ny][nx] is not None:
                return False
        return True

    def drop_tetromino(self):
        if self.is_valid_move(self.current_tetromino, 0, 1):
            self.current_tetromino.move(0, 1)
            return True
        else:
            self.lock_tetromino()
            return False

    def lock_tetromino(self):
        for x, y in self.current_tetromino.blocks:
            if y < 0:
                self.game_over = True
                return
            self.grid[y][x] = Gem(self.current_tetromino.color)

        # spawn next
        self.current_tetromino = self.next_tetromino
        self.current_tetromino.position = [GRID_WIDTH // 2 - 2, 0]
        self.next_tetromino = self.new_tetromino()

        # process clears with full chain reactions
        self.process_clears_and_chains()

    def process_clears_and_chains(self):
        while True:
            lines = self.clear_lines()
            matches = self.clear_matches()
            if lines == 0 and matches == 0:
                break
            # after any clear, let gems fall
            self.apply_gravity()

    def clear_lines(self):
        lines_to_clear = [
            r for r in range(GRID_HEIGHT)
            if all(self.grid[r][c] is not None for c in range(GRID_WIDTH))
        ]
        for row in reversed(lines_to_clear):
            del self.grid[row]
            self.grid.insert(0, [None] * GRID_WIDTH)
            self.score += 100  # points per line
        return len(lines_to_clear)

    def clear_matches(self):
        to_clear = set()
        # horizontal runs
        for r in range(GRID_HEIGHT):
            c = 0
            while c < GRID_WIDTH:
                if self.grid[r][c] is None:
                    c += 1
                    continue
                color = self.grid[r][c].color
                run_len = 1
                while c + run_len < GRID_WIDTH and self.grid[r][c + run_len] is not None and self.grid[r][c + run_len].color == color:
                    run_len += 1
                if run_len >= 3:
                    for k in range(run_len):
                        to_clear.add((r, c + k))
                c += run_len

        # vertical runs
        for c in range(GRID_WIDTH):
            r = 0
            while r < GRID_HEIGHT:
                if self.grid[r][c] is None:
                    r += 1
                    continue
                color = self.grid[r][c].color
                run_len = 1
                while r + run_len < GRID_HEIGHT and self.grid[r + run_len][c] is not None and self.grid[r + run_len][c].color == color:
                    run_len += 1
                if run_len >= 3:
                    for k in range(run_len):
                        to_clear.add((r + k, c))
                r += run_len

        # clear and score
        for (r, c) in to_clear:
            self.grid[r][c] = None
        self.score += 50 * len(to_clear)
        return len(to_clear)

    def apply_gravity(self):
        for c in range(GRID_WIDTH):
            stack = [self.grid[r][c] for r in range(GRID_HEIGHT) if self.grid[r][c] is not None]
            empties = [None] * (GRID_HEIGHT - len(stack))
            col_cells = empties + stack
            for r in range(GRID_HEIGHT):
                self.grid[r][c] = col_cells[r]
